  }
}];

// Anti-spam: ignora mensagens de sistemas, grupos e status
const chatId = $input.first().json.chatId || '';
const message = $input.first().json.message || '';

if (chatId.includes('@g.us')) {
  return [];
}
if (chatId === 'status@broadcast') {
  return [];
}
if (!message || message.trim() === '') {
  return [];
}

return $input.all();

const output = $input.first().json.output || $input.first().json.text || '';

let parsed;
try {
  const clean = output.replace(/```json|```/g, '').trim();
  parsed = JSON.parse(clean);
} catch(e) {
  parsed = { intencao: 'saudacao', resumo: 'mensagem não classificada', urgencia: 'normal' };
}

const prev = $('Preparar Contexto Triagem').first().json;

return [{
  json: {
    ...prev,
    intencao: parsed.intencao || 'saudacao',
    resumo: parsed.resumo || '',
    urgencia: parsed.urgencia || 'normal'
  }
}];

const consultas = $input.all();
const ctx = $('Extrair Intenção Classificada').first().json;

let futuras = consultas.filter(c => c.json.periodo === 'futuro');
let passadas = consultas.filter(c => c.json.periodo === 'passado');

let futurasTexto = 'Nenhuma consulta futura agendada.';
if (futuras.length > 0) {
  futurasTexto = futuras.map(c =>
    `[ID:${c.json.id}] ${c.json.tipo} | ${c.json.especialidade} | Dr(a). ${c.json.medico} | ${c.json.data} às ${c.json.hora} | ${c.json.local} | Status: ${c.json.status} | Protocolo: ${c.json.protocolo || 'N/A'}`
  ).join('\n');
}

let passadasTexto = 'Nenhum histórico disponível.';
if (passadas.length > 0) {
  passadasTexto = passadas.slice(0, 5).map(c =>
    `[ID:${c.json.id}] ${c.json.tipo} | ${c.json.especialidade} | ${c.json.data} | Status: ${c.json.status}`
  ).join('\n');
}

return [{ json: { ...ctx, futurasTexto, passadasTexto } }];

