// Detecta se a mensagem é uma resposta de pesquisa de satisfação
const message = $input.first().json.message || '';
const phone = $input.first().json.phone || '';
const chatId = $input.first().json.chatId || '';

const texto = message.trim().toLowerCase();
const nota = parseInt(texto);

// Verifica se é uma nota válida (1 a 5)
const ehNota = !isNaN(nota) && nota >= 1 && nota <= 5;

// Verifica se tem comentário junto (ex: '5 ótimo atendimento')
const partes = message.trim().split(' ');
const notaTexto = parseInt(partes[0]);
const comentario = partes.length > 1 ? partes.slice(1).join(' ') : '';

if (ehNota || (!isNaN(notaTexto) && notaTexto >= 1 && notaTexto <= 5)) {
  return [{
    json: {
      phone,
      chatId,
      message,
      nota: ehNota ? nota : notaTexto,
      comentario: comentario,
      ehRespostaPesquisa: true
    }
  }];
}

return [{
  json: {
    ...($input.first().json),
    ehRespostaPesquisa: false
  }
}];

const agendamento = $('🔍 Buscar Agendamento da Pesquisa').first().json;
const pesquisa = $('⭐ É Resposta de Pesquisa?').first().json;

if (!agendamento.agendamento_id) {
  return [{ json: { skip: true } }];
}

return [{
  json: {
    agendamentoId: agendamento.agendamento_id,
    pacienteId: agendamento.paciente_id,
    pacienteNome: agendamento.nome,
    tipo: agendamento.tipo,
    especialidade: agendamento.especialidade,
    medico: agendamento.medico,
    nota: pesquisa.nota,
    comentario: pesquisa.comentario || '',
    chatId: pesquisa.chatId,
    phone: pesquisa.phone
  }
}];

const nota = $('🧠 Preparar Dados da Avaliação').first().json.nota;
const nome = $('🧠 Preparar Dados da Avaliação').first().json.pacienteNome;
const medico = $('🧠 Preparar Dados da Avaliação').first().json.medico;
const chatId = $('🧠 Preparar Dados da Avaliação').first().json.chatId;

const estrelas = '⭐'.repeat(nota) + '☆'.repeat(5 - nota);

let mensagem = '';

if (nota >= 4) {
  mensagem = `${estrelas}

*Obrigado pela avaliação, ${nome}!* 💙

Ficamos muito felizes que sua experiência com Dr(a). ${medico} foi positiva!

Sua opinião nos ajuda a manter a excelência no atendimento.

_FUBEN — Excelência em saúde para você_ 🏥`;
} else if (nota === 3) {
  mensagem = `${estrelas}

*Obrigado pela avaliação, ${nome}!* 💙

Agradecemos seu retorno. Estamos trabalhando constantemente para melhorar nossos serviços.

Caso queira nos contar mais sobre sua experiência, pode responder aqui.

_FUBEN — Comprometidos com a sua saúde_ 🏥`;
} else {
  mensagem = `${estrelas}

*Obrigado pela avaliação, ${nome}.*

Lamentamos que sua experiência não tenha sido satisfatória. Seu retorno é extremamente importante para nós.

Um de nossos responsáveis entrará em contato para entender o que aconteceu e garantir que isso não se repita.

Pedimos sinceras desculpas pelo transtorno.

_FUBEN — Comprometidos com a sua saúde_ 🏥`;
}

return [{ json: { chatId, mensagem, nota } }];

const geral = $('📈 Buscar Indicadores Gerais').first().json;
const porMedico = $('👨‍⚕️ Indicadores por Médico').all();

const total = geral.total_avaliacoes || 0;
const media = geral.media_geral || 0;
const nps = geral.nps_score || 0;
const promotores = geral.promotores || 0;
const neutros = geral.neutros || 0;
const detratores = geral.detratores || 0;

let npsEmoji = nps >= 75 ? '🟢 Excelente' : nps >= 50 ? '🟡 Bom' : nps >= 0 ? '🟠 Regular' : '🔴 Crítico';
let mediaEmoji = media >= 4.5 ? '⭐⭐⭐⭐⭐' : media >= 3.5 ? '⭐⭐⭐⭐' : media >= 2.5 ? '⭐⭐⭐' : '⭐⭐';

let medicosTexto = '';
if (porMedico.length > 0 && porMedico[0].json.medico) {
  medicosTexto = porMedico.slice(0, 5).map((m, i) =>
    `${i + 1}. Dr(a). ${m.json.medico} (${m.json.especialidade}) — Média: ${m.json.media} | Avaliações: ${m.json.total}`
  ).join('\n');
} else {
  medicosTexto = 'Sem dados suficientes.';
}

const relatorio = `*📊 RELATÓRIO SEMANAL — FUBEN*\n*Satisfação de Pacientes*\n\n📅 Período: últimos 7 dias\n\n━━━━━━━━━━━━━━━━━━━━\n*VISÃO GERAL*\n━━━━━━━━━━━━━━━━━━━━\n📋 Total de avaliações: *${total}*\n${mediaEmoji} Média geral: *${media}/5.0*\n📌 NPS Score: *${nps}%* — ${npsEmoji}\n\n😊 Promotores (4-5): *${promotores}*\n😐 Neutros (3): *${neutros}*\n😞 Detratores (1-2): *${detratores}*\n\n━━━━━━━━━━━━━━━━━━━━\n*TOP PROFISSIONAIS*\n━━━━━━━━━━━━━━━━━━━━\n${medicosTexto}\n\n_FUBEN — Sistema Inteligente de Saúde_ 🏥`;

return [{ json: { relatorio } }];

const body = $input.first().json.body;

const notas = [
  body.avaliacoes?.atendimento || 0,
  body.avaliacoes?.espera     || 0,
  body.avaliacoes?.recepcao   || 0,
  body.avaliacoes?.estrutura  || 0
];

const media = notas.reduce((a, b) => a + b, 0) / notas.length;
const mediaFormatada = Math.round(media * 10) / 10;

const esc = (str) => (str || '').substring(0, 300);

return [{
  json: {
    paciente_nome:     esc(body.paciente),
    nps:               parseInt(body.nps) || 0,
    nota_atendimento:  parseInt(body.avaliacoes?.atendimento) || 0,
    nota_espera:       parseInt(body.avaliacoes?.espera)      || 0,
    nota_recepcao:     parseInt(body.avaliacoes?.recepcao)    || 0,
    nota_estrutura:    parseInt(body.avaliacoes?.estrutura)   || 0,
    media_geral:       mediaFormatada,
    com_atendimento:   esc(body.comentarios?.atendimento),
    com_espera:        esc(body.comentarios?.espera),
    com_recepcao:      esc(body.comentarios?.recepcao),
    com_estrutura:     esc(body.comentarios?.estrutura),
    comentario_geral:  esc(body.comentario_geral),
    alerta_qualidade:  (parseInt(body.nps) || 0) <= 7
  }
}];
